INSERT INTO `event_card` (`card_no`, `title`, `dynasty`, `location`, `description`, `weight`, `era`) VALUES
('EV001','涿鹿·黄帝崛起','先秦','涿鹿（今河北）','黄帝与炎帝在涿鹿之野展开华夏民族史上规模最大的部族战争，黄帝最终胜出，统一黄河流域。',100,'先秦'),('EV002','神农尝百草','先秦','荆楚地区','神农氏亲尝百草辨别药性，日遇七十二毒，以茶解之，开创中医药学之先河。',80,'先秦'),('EV003','阪泉·炎黄之战','先秦','阪泉（今山西）','黄帝与炎帝两大部落在阪泉之野三度交战，黄帝最终收服炎帝部族。',100,'先秦'),('EV004','蚩尤之乱','先秦','涿鹿（今河北）','九黎部落首领蚩尤率八十一部族作乱，呼风唤雨，黄帝与炎帝联手将其击败。',80,'先秦'),('EV005','伏羲创八卦','先秦','陈仓（今陕西）','伏羲氏仰观天文俯察地理，悟得阴阳变化之理，创制八卦。',80,'先秦'),('EV006','女娲补天','先秦','不周山（传说）','共工怒触不周山，天倾地裂，洪水泛滥。女娲炼五色石补天，救万民于水火。',100,'先秦'),('EV007','大禹治水','先秦','九州（黄河长江流域）','大禹承父遗志，改堵为疏导洪水，三过家门而不入，终平水患。',100,'先秦'),('EV008','禹王分九州','先秦','冀州（今河北）','大禹将天下划分为冀、兖、青、徐、扬、荆、豫、梁、雍九州。',50,'先秦'),('EV009','夏启继位','先秦','阳城（今河南）','大禹逝世后，启即天子之位，结束禅让制，建立世袭制夏朝。',80,'先秦'),('EV010','有扈氏之乱','先秦','甘（今陕西鄠县）','夏启继位，有扈氏不服，起兵反抗。夏启率六军征讨，大败有扈氏。',50,'先秦'),('EV011','太康失国','先秦','斟鄩（今河南巩义）','太康耽于游猎，被东夷族有穷氏首领后羿篡夺王位。',80,'先秦'),('EV012','少康复国','先秦','斟鄩（今河南）','少康在有仍氏、有虞氏帮助下积蓄力量，灭有穷氏，复兴夏朝。',100,'先秦'),('EV013','孔甲养龙','先秦','夏朝王都','夏王孔甲喜好养龙，不理朝政，天降灾异，夏朝国势渐衰。',50,'先秦'),('EV014','商汤灭夏','先秦','商丘（今河南）','成汤伐夏，鸣条之战，夏朝覆灭，商朝建立。',100,'先秦'),('EV015','伊尹辅政','先秦','商丘（今河南）','伊尹辅助商汤建立商朝，后又辅佐四代商王。',80,'先秦'),('EV016','太甲乱德','先秦','商朝王都','商王太甲暴虐乱德，伊尹将其放逐桐宫，三年后太甲改过，伊尹还政。',80,'先秦'),('EV017','盘庚迁殷','先秦','殷（今河南安阳）','商王盘庚迁都于殷，从此商朝政治稳定。',80,'先秦'),('EV018','武丁盛世','先秦','殷（今河南安阳）','商王武丁重用傅说为相，开疆拓土，商朝国力达到鼎盛。',100,'先秦'),('EV019','妇好征伐','先秦','殷（今河南安阳）','妇好是中国历史上有据可查的第一位女性军事统帅，率军征伐羌方等方国。',80,'先秦'),('EV020','周族兴起','先秦','关中地区','周族在古公亶父率领下迁居周原，励精图治，势力逐渐强盛。',80,'先秦'),('EV021','文王拘而演易','先秦','羑里（今河南汤阴）','周文王被商纣囚禁于羑里，推演八卦为六十四卦，作《周易》。',100,'先秦'),('EV022','武王伐纣','先秦','牧野（今河南新乡）','周武王在牧野大败商军，纣王自焚，商朝灭亡，周朝建立。',100,'先秦'),('EV023','周公辅政','先秦','镐京（今陕西西安）','周公旦辅佐成王，摄政七年，平定三监之乱，制定礼乐制度。',100,'先秦'),('EV024','成康之治','先秦','镐京（今陕西西安）','周成王和周康王在位期间，天下太平，刑错四十年不用。',80,'先秦'),('EV025','昭王南征','先秦','汉水流域','周昭王率军南征楚国，在汉水遭遇惨败，周朝军事力量开始衰落。',50,'先秦'),('EV026','穆王西征','先秦','西域','周穆王西征犬戎，远达天山各地，周朝疆域达到极盛。',80,'先秦'),('EV027','厉王专利','先秦','镐京（今陕西西安）','周厉王实行专利政策，垄断山林川泽，引发国人暴动，厉王被流放。',80,'先秦'),('EV028','共和行政','先秦','镐京（今陕西西安）','周厉王被流放后，召公和周公共同执政十四年，中国历史开始有确切纪年。',80,'先秦'),('EV029','宣王中兴','先秦','镐京（今陕西西安）','周宣王整顿朝政，南征荆蛮，北伐犬戎，周朝一度复兴。',80,'先秦'),('EV030','幽王烽火戏诸侯','先秦','骊山（今陕西西安）','周幽王烽火戏诸侯，失信于天下，申侯联合犬戎攻入镐京，西周覆亡。',100,'先秦'),('EV031','平王东迁','先秦','洛邑（今河南洛阳）','犬戎攻破镐京后，周平王在郑、秦、晋等诸侯护送下东迁洛邑，建立东周，春秋战国大时代由此开启。',80,'春秋初期'),('EV032','郑庄公克段','先秦','新郑（今河南）','郑庄公之弟共叔段在母亲姜氏支持下谋反，郑庄公先纵其骄，后命子封伐之，共叔段兵败出逃。',50,'春秋初期'),('EV033','齐桓称霸','先秦','临淄（今山东）','齐桓公小白在管仲辅佐下，以"尊王攘夷"为旗号，九合诸侯，一匡天下，成为春秋五霸之首。',100,'春秋初期'),('EV034','管仲改革','先秦','临淄（今山东）','管仲相齐，实行相地而衰征、盐铁专营、统一货币等改革，使齐国由弱转强，开创中国历史上第一次系统性变法。',100,'春秋初期'),('EV035','曹刿论战','先秦','长勺（今山东莱芜）','齐国伐鲁，曹刿于长勺之战中待齐军三鼓之后发起进攻，大败齐军，留下"一鼓作气"之千古战典。',50,'春秋初期'),('EV036','晋文称霸','先秦','绛县（今山西）','晋文公重耳流亡十九年，归国后励精图治，城濮之战大败楚军，成为春秋五霸之一。',100,'春秋中期'),('EV037','重耳流亡','先秦','列国','晋献公诸子争位，公子重耳被迫流亡列国十九年，终被秦穆公护送归晋，成就霸业。',100,'春秋中期'),('EV038','城濮之战','先秦','城濮（今山东鄄城）','晋文公与楚国争霸，两军大战于城濮。晋军退避三舍，后发制人，大败楚军，奠定晋国中原霸主地位。',80,'春秋中期'),('EV039','烛之武退秦师','先秦','汜南（今河南）','郑国老臣烛之武夜缒而出，面见秦穆公，以"亡郑陪邻"之理说服秦军撤退，孤身化解亡国危机。',100,'春秋中期'),('EV040','崤山之战','先秦','崤山（今河南）','秦晋围郑，秦军偷袭郑国途中，晋军联合姜戎在崤山设伏，全歼秦军，俘获秦军三帅。',50,'春秋中期'),('EV041','秦穆称霸西戎','先秦','雍州（今陕西）','秦穆公任用由余谋略，灭西戎十二国，开地千里，遂霸西戎，周襄王赐金鼓以示嘉奖。',50,'春秋中期'),('EV042','楚庄王问鼎','先秦','洛邑（今河南）','楚庄王率兵北伐，陈兵周郊，问九鼎之轻重，意图取代周朝。王孙满以"在德不在鼎"婉拒。',100,'春秋中期'),('EV043','邲之战','先秦','邲（今河南郑州）','楚庄王率军大败晋军于邲，晋军溃逃时争船渡河，自相残杀，楚国饮马黄河，霸业达于极盛。',80,'春秋中期'),('EV044','晏子使楚','先秦','郢都（今湖北）','齐国晏婴身材矮小，出使楚国，楚王三次侮辱晏子。晏子以"橘生淮南"之喻巧妙反击，维护了齐国尊严。',100,'春秋中期'),('EV045','孙武演兵','先秦','吴国（今江苏）','齐国军事家孙武以宫中一百八十名宫女演练阵法，宠妃轻视号令，孙武立斩二妃，宫女闻鼓肃然。',100,'春秋末期'),('EV046','伍子胥出亡','先秦','郢都（今湖北）','伍子胥之父伍奢被楚平王冤杀，伍子胥出亡吴国，"一夜白头"过昭关，后助吴王阖闾攻入郢都。',100,'春秋末期'),('EV047','吴越争霸','先秦','会稽（今浙江）','吴王夫差大败越王勾践于会稽，勾践入吴为奴三年，归国后卧薪尝胆，最终灭吴称霸。',100,'春秋末期'),('EV048','卧薪尝胆','先秦','会稽（今浙江）','越王勾践归国后，将苦胆悬于座位上方，坐卧即尝。十年生聚，十年教训，终于灭吴雪耻。',100,'春秋末期'),('EV049','三家分晋','先秦','绛县（今山西）','晋国被韩、赵、魏三家瓜分，晋静公被废，中国历史由此进入战国七雄时代。',80,'春秋末期'),('EV050','李悝变法','先秦','魏国（今河南）','魏文侯重用李悝实行变法，推行"平籴法"，编纂《法经》为中国第一部系统的成文法典。',100,'战国初期');
INSERT INTO `event_card` (`card_no`, `title`, `dynasty`, `location`, `description`, `weight`, `era`) VALUES
('EV051','吴起在楚','先秦','楚国','吴起自魏奔楚，辅佐楚悼王实行变法，南平百越，北却三晋，楚国国势大振。',100,'战国初期'),('EV052','商鞅变法','先秦','咸阳（今陕西）','卫鞅携带李悝《法经》入秦，辅佐秦孝公推行变法，废井田、开阡陌、奖励军功、推行县制。',100,'战国中期'),('EV053','围魏救赵','先秦','桂陵（今河南长垣）','孙膑率齐军不直接救赵，而围攻魏都大梁，庞涓回师，在桂陵中伏被擒，留下经典战例。',100,'战国中期'),('EV054','马陵之战','先秦','马陵（今山东）','孙膑用减灶计诱庞涓深入，在马陵道设伏，万弩齐发，庞涓兵败自刎，齐军大破魏军。',80,'战国中期'),('EV055','合纵连横','先秦','六国','苏秦以合纵之术游说六国，身佩六国相印；张仪以连横之策破合纵，游说各国亲秦。',100,'战国中期'),('EV056','张仪欺楚','先秦','楚国','张仪以商於六百里地诱骗楚怀王与齐国断交，楚怀王贪利上当，最终客死秦国，留下千古笑柄。',50,'战国中期'),('EV057','胡服骑射','先秦','邯郸（今河北）','赵武灵王推行胡服骑射改革，摒弃中原宽袍大袖，赵国军事实力大增，灭中山国，辟地千里。',100,'战国中期'),('EV058','屈原沉江','先秦','汨罗江（今湖南）','屈原为楚国大夫，因谗言被放逐，忧国忧民，作《离骚》《天问》。楚都被秦攻破后，悲愤投汨罗江而死。',100,'战国末期'),('EV059','蔺相如完璧归赵','先秦','渑池（今河南）','蔺相如奉命出使，以大智大勇于渑池会上斥秦王无礼，完璧归赵，留下"价值连城"典故。',100,'战国末期'),('EV060','将相和','先秦','邯郸（今河北）','蔺相如以"先国家之急"对老将廉颇处处忍让，终使廉颇感悟，亲自负荆请罪，留下将相和千古佳话。',100,'战国末期'),('EV061','长平之战','先秦','长平（今山西高平）','秦将白起大败赵括于长平，坑杀赵军四十万降卒，赵国元气大伤，秦国统一六国的进程大大加快。',80,'战国末期'),('EV062','白起坑卒','先秦','长平（今山西）','长平之战后，白起坑杀四十万赵军降卒，仅放回二百四十名年幼者，天下震惊。',80,'战国末期'),('EV063','信陵君窃符','先秦','大梁（今河南开封）','秦围赵都邯郸，信陵君魏无忌窃取魏王兵符，率军救赵，留下"窃符救赵"之千古义举。',100,'战国末期'),('EV064','秦王灭周','先秦','洛阳（今河南）','秦昭王派将军攻西周，西周文公投降，献出三十六城，周赧王被废为庶人，周朝八百余年统治至此终结。',80,'战国末期'),('EV065','嬴政亲政','秦汉','咸阳（今陕西）','秦王嬴政铲除嫪毐叛乱，罢免吕不韦，开始真正独掌国政，此后三十年东出扫灭六国，建立第一个大一统帝国。',80,'秦王亲政时期'),('EV066','秦灭韩','秦汉','新郑（今河南）','公元前230年，秦将内史腾率军攻韩，俘虏韩王安，韩亡。韩国成为六国中第一个被灭亡的国家。',80,'秦灭六国'),('EV067','秦灭赵','秦汉','邯郸（今河北）','秦将王翦、杨端和分两路攻赵，公元前228年破邯郸，俘虏赵王迁，赵国亡。',80,'秦灭六国'),('EV068','荆轲刺秦','秦汉','咸阳（今陕西）','燕太子丹以荆轲为刺客，携督亢地图与樊於期人头入秦行刺。荆轲刺秦不中，被秦王侍卫斩杀，事败后秦大怒伐燕。',100,'战国末期'),('EV069','秦灭燕','秦汉','蓟城（今北京）','秦将王翦大破燕军于易水河畔，燕王喜杀太子丹求和不成，秦将李信追至辽东，俘燕王喜，燕亡。',80,'秦灭六国'),('EV070','秦灭魏','秦汉','大梁（今河南开封）','公元前225年，秦将王贲引黄河水灌大梁城三月，城破，魏王假投降，魏亡。',80,'秦灭六国'),('EV071','王翦灭楚','秦汉','寿春（今安徽）','秦将王翦率六十万大军伐楚，坚壁不战，养精蓄锐，待楚军松懈后发起进攻，俘虏楚王负刍，楚亡。',100,'秦灭六国'),('EV072','秦灭齐','秦汉','临淄（今山东）','公元前221年，秦将王贲率军从燕国南部攻齐，兵不血刃直入临淄，齐王建不战而降，六国统一，秦始皇建立秦帝国。',80,'秦灭六国'),('EV073','统一度量衡','秦汉','咸阳（今陕西）','秦始皇统一六国后，下令统一度量衡、货币、文字（小篆），建立郡县制，开创两千年中央集权政治制度的基础。',100,'秦朝初期'),('EV074','修筑万里长城','秦汉','北方边疆','秦始皇下令将秦、赵、燕原有长城连接并延伸，西起临洮，东至辽东，绵延万里，成为人类历史上最宏伟的防御工程。',100,'秦朝初期'),('EV075','秦始皇焚书','秦汉','咸阳（今陕西）','公元前213年，秦始皇采纳李斯建议，下令焚烧《诗》《书》及诸子百家典籍，"焚书"钳制了思想自由。',50,'秦朝中期'),('EV076','秦始皇坑儒','秦汉','咸阳（今陕西）','秦始皇因方士卢生、侯生讥讽皇帝而大怒，将四百六十余名儒生活埋于咸阳城外，史称"坑儒"。',50,'秦朝中期'),('EV077','徐福东渡','秦汉','琅琊（今山东）','秦始皇为求长生不老药，命方士徐福率三千童男童女出海东渡寻仙，徐福一去不返。',100,'秦朝中期'),('EV078','蒙恬北击匈奴','秦汉','河套地区','秦将蒙恬率三十万大军北击匈奴，收复河套地区，修筑直道，使匈奴不敢南渡牧马。',50,'秦朝初期'),('EV079','修筑直道','秦汉','北方边疆','蒙恬修筑从咸阳至九原的直道，全长千余里，路基宽阔笔直，是世界上最早的高速公路之一。',50,'秦朝初期'),('EV080','秦始皇驾崩','秦汉','沙丘（今河北）','公元前210年，秦始皇东巡途中病逝于沙丘平台。赵高与李斯合谋篡改遗诏，赐死扶苏，立胡亥为帝。',100,'秦朝中期'),('EV081','指鹿为马','秦汉','咸阳（今陕西）','赵高为试探群臣态度，献给秦二世一匹鹿，说是马。群臣有人直言是鹿，赵高将直言者尽皆治罪。',100,'秦朝末期'),('EV082','大泽乡起义','秦汉','大泽乡（今安徽）','陈胜、吴广因雨误期，按秦法当斩，遂率九百戍卒揭竿而起，喊出"王侯将相宁有种乎"的口号。',100,'秦朝末期'),('EV083','陈胜建张楚','秦汉','陈县（今河南）','陈胜吴广在大泽乡起义后，率军攻占陈县，陈胜被推举为王，建国号"张楚"，各地纷纷响应。',50,'秦朝末期'),('EV084','项梁项羽起兵','秦汉','吴县（今江苏苏州）','项梁项羽叔侄在会稽起兵，率八千江东子弟渡江而西，成为反秦主力，项羽勇冠三军。',100,'秦末汉初'),('EV085','平王东迁','东周','洛邑','犬戎攻破镐京，周平王东迁洛邑，建立东周，春秋战国大时代由此开启。',100,'东周'),('EV086','郑庄公小霸','东周','新郑','郑庄公在繻葛之战击败周联军，箭射周桓王，打破了周天子不可侵犯的神话。',80,'东周'),('EV087','齐桓公称霸','东周','临淄','齐桓公在管仲辅佐下九合诸侯，成为春秋首霸。',100,'东周'),('EV088','管仲改革','东周','临淄','管仲在齐国推行改革，通货积财，富国强兵，助齐桓公称霸。',80,'东周'),('EV089','曹刿论战','东周','长勺','齐鲁长勺之战，曹刿提出一鼓作气再而衰三而竭，大败齐军。',80,'东周'),('EV090','假道灭虢','东周','虞国','晋国向虞国借道伐虢，宫之奇识破阴谋，虞国国君不听，唇亡齿寒。',80,'东周'),('EV091','重耳流亡','东周','列国','晋国公子重耳流亡列国十九年，饱受磨难，终返国即位，是为晋文公。',100,'东周'),('EV092','晋文公践土之盟','东周','践土（今河南原阳）','晋文公在城濮之战大败楚军后，践土会盟，周襄王册封他为侯伯。',100,'东周'),('EV093','城濮之战','东周','城濮（今山东鄄城）','晋楚两国在城濮决战，晋文公退避三舍，诱敌深入，大败楚军。',100,'东周'),('EV094','秦穆公称霸西戎','东周','雍城（今陕西凤翔）','秦穆公任用由余，灭西戎十二国，开地千里，遂霸西戎。',80,'东周'),('EV095','崤山之战','东周','崤山','晋军在崤山伏击秦军，全歼秦军三千余人，是春秋时期著名伏击战。',80,'东周'),('EV096','楚庄王问鼎','东周','洛邑','楚庄王率军北伐，在洛邑郊外陈兵示威，询问九鼎大小轻重，有取周之意。',80,'东周'),('EV097','邲之战','东周','邲（今河南荥阳）','晋楚邲之战，晋军大败，楚庄王饮马黄河，确立楚国霸权。',100,'东周'),('EV098','孙武练兵','东周','吴国','孙子以兵法见吴王阖闾，斩吴王两位宠姬练兵，著《孙子兵法》。',80,'东周'),('EV099','伍子胥掘墓鞭尸','东周','郢都','伍子胥率吴军攻破郢都，掘楚平王之墓，鞭尸三百，以报父仇。',80,'东周'),('EV100','越王勾践卧薪尝胆','东周','会稽山','越王勾践兵败会稽，十年生聚，十年教训，终于灭吴复国。',100,'东周');
INSERT INTO `event_card` (`card_no`, `title`, `dynasty`, `location`, `description`, `weight`, `era`) VALUES
('EV101','范蠡泛舟五湖','东周','太湖','范蠡辅佐勾践灭吴后，功成身退，泛舟五湖，改名陶朱公经商。',80,'东周'),('EV102','三家分晋','东周','晋国','韩、赵、魏三家大夫瓜分晋国，晋国灭亡，战国七雄局面形成。',100,'东周'),('EV103','商鞅变法','东周','咸阳','商鞅在秦国推行变法，废井田、开阡陌，奖励军功，秦国由此强大。',100,'东周'),('EV104','围魏救赵','战国','邯郸','齐国军师孙膑用围魏救赵之计，在桂陵大败魏军，庞涓被俘。',80,'战国'),('EV105','马陵之战','战国','马陵','孙膑在马陵设伏，庞涓兵败自刎，齐国威震诸侯。',80,'战国'),('EV106','苏秦合纵','战国','六国','苏秦以合纵之术游说六国，身佩六国相印，率诸侯抗秦。',100,'战国'),('EV107','张仪连横','战国','咸阳','张仪以连横之术破合纵，瓦解六国联盟，为秦统一六国奠定基础。',80,'战国'),('EV108','胡服骑射','战国','邯郸','赵武灵王推行胡服骑射改革，学习匈奴骑射战术，赵国军力大增。',80,'战国'),('EV109','屈原沉江','战国','汨罗江','屈原忧国忧民，因谗言被放逐，闻国都郢被秦军攻破，投汨罗江而亡。',100,'战国'),('EV110','完璧归赵','战国','咸阳','蔺相如携和氏璧出使秦国，在秦王面前完璧归赵，维护了赵国尊严。',80,'战国'),('EV111','将相和','战国','邯郸','蔺相如与廉颇将相和好，留下将相和佳话，赵国一时强盛。',80,'战国'),('EV112','长平之战','战国','长平','秦赵长平大战，赵括纸上谈兵，四十五万赵军被坑杀。',100,'战国'),('EV113','窃符救赵','战国','邯郸','信陵君窃取魏王兵符，率军救赵，在邯郸大败秦军。',100,'战国'),('EV114','吕不韦奇货可居','战国','邯郸','商人吕不韦发现质子异人，认为奇货可居，倾家荡产资助其登上秦王之位。',80,'战国'),('EV115','封狼居胥','秦汉','狼居胥山（今蒙古）','霍去病率军北击匈奴，深入漠北，登狼居胥山筑坛祭天，成为中国武将最高荣誉的代称。',100,'西汉鼎盛期'),('EV116','秦王政统一六国','秦','咸阳','秦王政灭六国，建立秦朝，自称始皇帝，中国进入大一统时代。',100,'秦'),('EV117','秦始皇修长城','秦','北方边境','秦始皇修筑万里长城，以防匈奴南侵，动用民夫数十万。',80,'秦'),('EV118','秦始皇焚书坑儒','秦','咸阳','秦始皇焚烧诗书，坑杀方士儒生四百六十余人。',100,'秦'),('EV119','秦始皇崩于沙丘','秦','沙丘行宫','秦始皇病逝于沙丘，赵高李斯矫诏杀扶苏立胡亥。',100,'秦'),('EV120','陈胜吴广起义','秦','大泽乡','陈胜吴广在大泽乡斩木为兵，揭竿而起，天下响应。',100,'秦'),('EV121','巨鹿之战','秦','巨鹿','项羽破釜沉舟，在巨鹿大败秦军，奠定灭秦基础。',100,'秦'),('EV122','刘邦入咸阳','秦','咸阳','刘邦率军攻入咸阳，子婴投降，秦朝覆灭。',80,'秦'),('EV123','鸿门宴','秦','鸿门','项羽设鸿门宴欲杀刘邦，项伯、张良、樊哙相助，刘邦全身而退。',100,'秦'),('EV124','董卓进京·乱政之源','东汉末','洛阳','董卓率西凉铁骑进京，废少帝立献帝，迁都长安，焚毁洛阳，诸侯联军讨伐，东汉名存实亡。',80,'东汉末'),('EV125','十八路诸侯讨董','东汉末','洛阳','关东诸侯联军推袁绍为盟主，曹操、孙坚等十八路诸侯会盟讨伐董卓，这是东汉末年最大规模的军事行动。',80,'东汉末'),('EV126','孙坚跨江击刘表','东汉末','襄阳','孙坚率部跨江攻刘表，被乱箭射杀，一代猛将陨落，其子孙策日后继承遗志开创江东基业。',50,'东汉末'),('EV127','王允献貂蝉·连环计','东汉末','长安','司徒王允以貂蝉为饵，设连环计离间董卓与吕布，吕布杀死董卓，结束了董卓专权的黑暗时期。',100,'东汉末'),('EV128','曹操挟天子以令诸侯','东汉末','许昌','曹操迎汉献帝迁都许昌，开始了"挟天子以令诸侯"的政治攻势，在政治上占据了绝对优势。',100,'东汉末'),('EV129','曹操破吕布','东汉末','下邳','曹操围攻吕布于下邳，吕布部下叛变，吕布被擒后缢杀，曹操统一了徐州地区。',50,'东汉末'),('EV130','袁绍磐河之战','东汉末','磐河','袁绍与公孙瓒在磐河激战，袁绍诈降夺冀州，公孙瓒败走易京，东汉北方格局就此奠定。',50,'东汉末'),('EV131','官渡之战·以少胜多','东汉末','官渡','袁绍率十万大军南攻曹操，曹操以两万兵力在官渡相持，最终火烧乌巢，以少胜多奠定了统一北方的基础。',100,'东汉末'),('EV132','曹操北征乌桓','东汉末','柳城','曹操在平定河北后，北征乌桓，白狼山之战大破乌桓联军，北方边患基本解除。',50,'东汉末'),('EV133','刘备败走当阳','东汉末','当阳','曹操南征荆州，刘备率十万百姓南逃，曹操精骑在当阳长坂追上，刘备弃妻弃子，仅率数十骑逃走。',80,'东汉末'),('EV134','鲁肃榻上策','东汉末','江东','鲁肃向孙权献榻上策，建议东吴立足江东，联合刘备共拒曹操，奠定了三分天下的战略基础。',80,'东汉末'),('EV135','孙权继位江东','东汉末','吴郡','孙策遇刺身亡，孙权继位为江东之主，在张昭、周瑜辅佐下，逐步稳固了江东六郡的统治。',50,'东汉末'),('EV136','赤壁崖·东风骤起','东汉末','赤壁','曹操统一北方后南取荆州，刘备败走夏口，孙权联合刘备对抗曹操，周瑜巧借东风，火烧连营，曹军大败。',100,'东汉末'),('EV137','曹操收取荆州','东汉末','襄阳','赤壁战败后，曹操退回北方，留曹仁守江陵，孙刘联军追击，荆州归属暂时三分。',50,'东汉末'),('EV138','周瑜病逝巴丘','东汉末','巴丘','周瑜提出取蜀计划，病逝于巴丘，年仅三十六岁，临终举荐鲁肃接任，都督之位后由鲁肃接掌。',80,'东汉末'),('EV139','张松献益州地图','东汉末','成都','益州别驾张松出使曹操被拒，转投刘备，将益州地形图献给刘备，为刘备日后取益州埋下伏笔。',80,'东汉末'),('EV140','刘备取益州','东汉末','成都','刘璋请刘备入川助战，刘备趁机夺取涪城后进攻成都，刘璋出降，刘备自领益州牧。',80,'东汉末'),('EV141','黄忠定军山斩夏侯渊','东汉末','定军山','刘备进攻汉中，老将黄忠在定军山刀劈夏侯渊，曹军大震，此战奠定了刘备夺取汉中的基础。',100,'东汉末'),('EV142','曹操汉中称王','东汉末','汉中','曹操击退刘备后，进封魏王，加九锡，奠定了曹魏代汉的基础，三国鼎立的局面正式形成。',80,'东汉末'),('EV143','关羽水淹七军','东汉末','樊城','关羽北伐襄阳，围曹仁于樊城，于禁七军被洪水淹没，全军覆没，关羽威震华夏，曹操几欲迁都避其锋芒。',100,'东汉末'),('EV144','吕蒙白衣渡江','东汉末','荆州','吕蒙称病让陆逊代守，陆逊写信示弱关羽。关羽抽调荆州兵力北伐，吕蒙率军白衣渡江，袭取荆州。',100,'东汉末'),('EV145','关羽败走麦城','东汉末','麦城','吕蒙占据荆州后，关羽北伐军心瓦解，被徐晃击败，退守麦城，最终突围时被马忠擒获遇害。',80,'东汉末'),('EV146','曹丕代汉建魏','三国','洛阳','曹操死后，曹丕逼迫汉献帝禅位，建立魏国，东汉正式灭亡，中国历史进入三国时代。',100,'三国时期'),('EV147','刘备称帝成都','三国','成都','刘备以汉室宗亲身份在成都称帝，国号汉，史称蜀汉，封诸葛亮为丞相。',80,'三国时期'),('EV148','刘备夷陵复仇','三国','夷陵','刘备为给关羽报仇，率全国之兵东征孙权，在夷陵被陆逊以火攻击败，蜀汉精锐损失殆尽。',100,'三国时期'),('EV149','陆逊火烧连营','三国','夷陵','陆逊在夷陵坚守数月，以逸待劳，采用火攻战术，大破刘备四十余营，刘备败逃永安。',100,'三国时期'),('EV150','刘备托孤白帝城','三国','白帝城','刘备败退白帝城，临终托孤于诸葛亮，将刘禅和蜀汉江山托付，诸葛亮泣不成声，承诺鞠躬尽瘁。',100,'三国时期');
INSERT INTO `event_card` (`card_no`, `title`, `dynasty`, `location`, `description`, `weight`, `era`) VALUES
('EV151','七擒孟获','三国','南中','诸葛亮南征孟获，采取攻心为上的策略，七擒七纵，孟获终于心服，南中从此安定。',100,'三国时期'),('EV152','诸葛亮第一次出祁山','三国','祁山','诸葛亮上《出师表》，率军北伐曹魏，出祁山攻取天水、南安、安定三郡，姜维投降。',80,'三国时期'),('EV153','马谡失街亭','三国','街亭','诸葛亮第一次北伐，派马谡守街亭，马谡违背诸葛亮的部署，被张郃击败，北伐大好形势毁于一旦。',100,'三国时期'),('EV154','诸葛亮空城计','三国','西城','司马懿率军攻打西城，诸葛亮城中兵少，于是大开城门，自己在城楼抚琴，司马懿怀疑有伏兵，引兵退去。',100,'三国时期'),('EV155','诸葛亮第二次出祁山','三国','祁山','诸葛亮二出祁山，围攻陈仓，郝昭坚守二十余日，蜀军粮尽退兵。',50,'三国时期'),('EV156','诸葛亮第三次出祁山','三国','祁山','诸葛亮三出祁山，夺取武都、阴平二郡，留兵据守，退兵时斩杀张郃。',50,'三国时期'),('EV157','诸葛亮第五次北伐','三国','五丈原','诸葛亮五出祁山，与司马懿对峙于五丈原，司马懿坚守不出，诸葛亮积劳成疾，病逝于五丈原。',100,'三国时期'),('EV158','姜维继承遗志','三国','成都','诸葛亮死后，姜维继承北伐遗志，十一次兴兵伐魏，但蜀汉国力有限，最终未能成功。',80,'三国时期'),('EV159','司马懿高平陵之变','三国','洛阳','司马懿趁曹爽陪曹芳祭扫高平陵之机，发动政变控制洛阳，曹爽投降，后被灭族，司马氏掌权。',100,'三国时期'),('EV160','司马昭弑君','三国','洛阳','魏帝曹髦不甘为司马氏傀儡，率宫人讨伐司马昭，被成济弑杀，司马昭另立曹奂为帝。',100,'三国时期'),('EV161','邓艾偷渡阴平','三国','阴平','邓艾率军从阴平小道翻山越岭，直插江油，蜀军措手不及，绵竹关被破，成都门户洞开。',100,'三国时期'),('EV162','刘禅投降邓艾','三国','成都','邓艾兵临成都，刘禅在谯周劝说下开城投降，蜀汉灭亡，历二帝四十三年。',80,'三国时期'),('EV163','钟会邓艾之死','三国','成都','钟会据成都谋反，姜维假意与钟会联合，企图恢复蜀汉。事败，钟会、姜维、邓艾皆死于乱军之中。',100,'三国时期'),('EV164','晋灭吴·三分归一','三国','建业','晋军水陆并进，王濬楼船东下，杜预率军攻占江陵，孙皓投降，东吴灭亡，三国归晋。',100,'三国时期'),('EV165','司马炎代魏建晋','西晋','洛阳','司马昭死后，司马炎逼迫魏帝曹奂禅位，建立晋朝，史称西晋，中国短暂统一。',80,'西晋初期'),('EV166','晋武帝分封诸王','西晋','洛阳','晋武帝大封宗室二十七王，赋予兵权，欲以藩王屏卫皇室，却为日后的八王之乱埋下祸根。',50,'西晋初期'),('EV167','石崇王恺斗富','西晋','洛阳','石崇与王恺争豪斗富，晋武帝暗助王恺，赐其二尺高的珊瑚树，石崇将其打碎，赔以六株更高的。',50,'西晋'),('EV168','晋武帝立痴愚太子','西晋','洛阳','晋武帝明知太子司马衷痴愚，仍坚持立他为太子，留下千古笑柄，也为八王之乱和五胡乱华埋下伏笔。',50,'西晋'),('EV169','贾南风干政·八王之乱','西晋','洛阳','惠帝皇后贾南风专权，废杀太子，引发八王之乱，十六年战乱导致西晋元气大伤。',100,'八王之乱'),('EV170','永嘉之乱·五胡乱华','西晋','洛阳','匈奴刘渊攻破洛阳，俘虏晋怀帝，纵兵焚掠，中原士民大批南渡，史称永嘉之乱。',100,'五胡乱华'),('EV171','晋元帝南渡建康','东晋','建康','晋琅琊王司马睿在王导辅佐下南渡建康，建立东晋，中原文明开始大规模南移。',100,'东晋初期'),('EV172','王羲之兰亭序','东晋','会稽山阴','王羲之与友人会聚于会稽山阴之兰亭，行修禊事，王羲之酒酣作《兰亭集序》，被誉为天下第一行书。',100,'东晋'),('EV173','恒温北伐','东晋','长安','桓温三次北伐，曾收复洛阳，但最终被前燕击败，北伐成果付诸东流。',80,'东晋'),('EV174','淝水之战·风声鹤唳','东晋','淝水','前秦苻坚率八十万大军南征，谢安以八万北府兵迎战，东晋奇迹般大胜，前秦从此一蹶不振。',100,'淝水之战'),('EV175','谢安围棋退秦兵','东晋','建康','淝水之战时，谢安在东山与客人下棋，捷报传来，他看完后继续下棋，神色如常。',80,'东晋'),('EV176','谢安东山再起','东晋','东山','谢安隐居东山多年，桓温请他出山，他以国家大义为重再度出仕，成为东晋的柱石之臣。',50,'东晋'),('EV177','苻坚淝水大败','东晋','淝水','苻坚在淝水之战中大败，前秦帝国土崩瓦解，苻坚本人也在日后被姚苌所杀。',80,'东晋'),('EV178','刘裕北伐灭南燕','东晋','广固','刘裕率北府兵北伐，攻灭南燕，慕容超被俘送建康斩首，这是东晋历史上为数不多的成功北伐。',80,'东晋'),('EV179','刘裕灭后秦','东晋','长安','刘裕再度北伐，攻灭后秦，收复长安、洛阳，但刘裕急于回朝夺权，留下幼子守长安，夏国趁机夺回。',80,'东晋'),('EV180','刘宋建立·宋武帝','南北朝','建康','刘裕代晋建宋，史称刘宋，刘宋是中国南北朝时期南朝第一个朝代，开创寒门掌权的局面。',80,'南北朝'),('EV181','元嘉之治','南北朝','建康','宋文帝刘义隆在位期间，励精图治，元嘉年间成为南朝最繁荣的时期，史称元嘉之治。',80,'南北朝'),('EV182','元嘉北伐','南北朝','黄河流域','宋文帝三次北伐，意图收复中原，但均遭失败，尤其是第二次被北魏太武帝拓跋焘打得大败。',80,'南北朝'),('EV183','宋孝武帝改革','南北朝','建康','宋孝武帝刘骏即位后实行改革，削弱藩王势力，但本人也以暴政著称。',50,'南北朝'),('EV184','南朝宋内乱','南北朝','建康','宋明帝刘彧弑杀前废帝刘子业，但刘子业之弟刘子勋随即起兵讨伐，宋朝陷入内战。',50,'南北朝'),('EV185','刘裕北伐·寄奴北定中原','南北朝','长安','刘裕率北府兵北伐，灭后秦，收复洛阳、长安，是东晋历史上最接近统一全国的一次北伐。',100,'南北朝'),('EV186','萧道成代宋建齐','南北朝','建康','萧道成逼迫宋顺帝禅位，建立南齐，南朝进入萧齐时代，萧道成提倡节俭。',50,'南北朝'),('EV187','齐高帝改革','南北朝','建康','齐高帝萧道成提倡节俭，改革政治，但萧齐仅维持二十余年便被萧衍取代。',50,'南北朝'),('EV188','萧衍代齐建梁','南北朝','建康','萧衍起兵攻入建康，取代南齐建立梁朝，萧衍就是历史上著名的梁武帝。',80,'南北朝'),('EV189','梁武帝侒佛','南北朝','建康','梁武帝三次舍身同泰寺为奴，群臣以巨金赎身，国库为之一空，佞佛成为梁朝衰落的重要原因。',80,'南北朝'),('EV190','侯景之乱','南北朝','建康','侯景之乱是南北朝最大的战乱，侯景攻破建康，梁武帝被困饿死，建康化为废墟。',100,'南北朝'),('EV191','陈霸先建立南陈','南北朝','建康','陈霸先平定侯景之乱后代梁建陈，是南朝最后一个朝代，疆域也是南朝中最小的。',80,'南北朝'),('EV192','北魏统一北方','南北朝','平城','拓跋珪建立北魏，逐步统一北方黄河流域，中国进入南北朝对峙时期。',80,'南北朝'),('EV193','孝文帝汉化改革','南北朝','洛阳','北魏孝文帝实行全面汉化改革，迁都洛阳，改汉姓，穿汉服，说汉语，与鲜卑旧贵族矛盾激化。',100,'南北朝'),('EV194','孝文帝迁都洛阳','南北朝','洛阳','孝文帝力排众议，将北魏都城从平城迁至洛阳，全面推行汉化，这是中国历史上最重要的民族融合事件之一。',100,'南北朝'),('EV195','北魏分裂为东西魏','南北朝','洛阳/长安','北魏孝武帝不满高欢专权，投奔宇文泰。高欢另立元善见为帝，迁都邺城，北魏分裂为东魏和西魏。',80,'南北朝'),('EV196','高欢与宇文泰对峙','南北朝','洛阳','高欢控制东魏，宇文泰控制西魏，两人多次交战各有胜负，形成均势，中国北方陷入东西对峙。',80,'南北朝'),('EV197','西魏建立府兵制','南北朝','长安','宇文泰创立府兵制，建立八柱国十二大将军制度，这是中国历史上重要的军事制度创新。',80,'南北朝'),('EV198','北齐代东魏','南北朝','邺城','高欢之子高洋逼迫东魏孝静帝禅位，建立北齐，北齐富裕但政治腐败，最终被北周所灭。',50,'南北朝'),('EV199','北周代西魏','南北朝','长安','宇文泰之侄宇文护逼迫西魏恭帝禅位，建立北周，后灭北齐统一北方。',50,'南北朝'),('EV200','周武帝灭佛','南北朝','长安','周武帝宇文邕下令灭佛，毁佛寺还俗僧众三百万余人，增强国力，为灭北齐统一北方奠定了基础。',80,'南北朝');
INSERT INTO `event_card` (`card_no`, `title`, `dynasty`, `location`, `description`, `weight`, `era`) VALUES
('EV201','北周灭北齐','南北朝','邺城','周武帝率军攻灭北齐，统一北方，中国结束了近半个世纪的北朝对峙。',80,'南北朝'),('EV202','杨坚代周建隋','隋','长安','杨坚以外戚身份辅政，后逼迫北周静帝禅位，建立隋朝，是为隋文帝，中国即将再次统一。',100,'隋朝建立'),('EV203','陈后主亡国','南北朝','建康','陈后主陈叔宝荒废朝政，宠爱张丽华，隋军攻破建康，陈朝灭亡，南北朝结束。',80,'南北朝'),('EV204','梁武帝饿死台城','南北朝','建康','侯景攻破台城，梁武帝萧衍被囚禁于净居殿，饥渴而死，一代帝王结局凄惨。',80,'南北朝'),('EV205','祖冲之推算圆周率','南北朝','建康','祖冲之计算出圆周率在3.1415926和3.1415927之间，这一成果领先世界近千年。',50,'南北朝'),('EV206','范缜神灭论','南北朝','建康','范缜发表《神灭论》，反对佛教的灵魂不灭说，是中国古代重要的无神论思想。',50,'南北朝'),('EV207','郦道元注水经','南北朝','北方各地','郦道元为《水经》作注，写成《水经注》，是中国古代最重要的地理学著作之一。',50,'南北朝'),('EV208','贾思勰齐民要术','南北朝','山东','贾思勰写成《齐民要术》，是中国现存最早的完整农书，系统总结了黄河流域的农业生产经验。',50,'南北朝'),('EV209','钟嵘诗品','南北朝','建康','钟嵘写成《诗品》，是中国最早的诗歌理论专著，将汉魏以来的诗人分为上中下三品。',50,'南北朝'),('EV210','刘勰文心雕龙','南北朝','建康','刘勰写成《文心雕龙》，是中国第一部系统的文学理论著作，对后世文学批评影响深远。',50,'南北朝'),('EV211','北魏云冈石窟','南北朝','大同','北魏在平城开凿云冈石窟，塑造了五万多尊佛像，这是中国最早的佛教石窟之一。',80,'南北朝'),('EV212','北魏龙门石窟','南北朝','洛阳','北魏迁都洛阳后，开凿龙门石窟，佛像雕刻艺术达到高峰，与云冈石窟并称中国两大石窟。',80,'南北朝'),('EV213','玉壁之战','南北朝','玉壁','东魏高欢率十万大军攻西魏玉壁城，韦孝宽死守五十余日，高欢久攻不克，忧愤成疾而退兵。',80,'南北朝'),('EV214','陈朝末年·后主荒淫','南北朝','建康','陈后主每日与妃嫔游宴，作《玉树后庭花》等艳词，隋军已陈兵江北，后主依然歌舞升平。',80,'南北朝'),('EV215','隋灭陈·统一天下','隋','建康','韩擒虎、贺若弼分路攻陈，隋军攻入建康，陈后主与张丽华躲入景阳宫井中，被俘，陈朝灭亡。',100,'隋朝建立'),('EV216','隋文帝创建科举制','隋','长安','隋文帝废除九品中正制，创立科举制度，通过考试选拔人才，这是中国历史上最重要的政治制度创新之一。',100,'隋朝'),('EV217','隋炀帝营建东都','隋','洛阳','隋炀帝下令营建东都洛阳，每月役使二百万人，宫殿壮丽辉煌，是隋炀帝劳民伤财的举措之一。',80,'隋朝'),('EV218','隋炀帝开凿大运河','隋','洛阳至杭州','隋炀帝征发数百万民夫开凿大运河，沟通海河、黄河、淮河、长江、钱塘江五大水系，全长二千余里。',100,'隋朝'),('EV219','隋炀帝三征高句丽','隋','辽东','隋炀帝三次亲征高句丽，均遭失败，损失惨重，民不聊生，直接引发了隋末农民大起义。',100,'隋朝'),('EV220','隋炀帝游江都','隋','江都','隋炀帝乘龙舟游江都，奢华无度，随从十几万人，沿途百姓供给负担极重。',50,'隋朝'),('EV221','杨玄感黎阳造反','隋','黎阳','杨玄感在黎阳起兵反隋，是隋朝第一起大规模贵族叛乱，许多人以为隋朝天下即将大乱。',80,'隋朝'),('EV222','瓦岗寨起义','隋','瓦岗','翟让在瓦岗寨聚众起义，李密献计夺取洛口仓，瓦岗军成为隋末最强的农民起义军。',100,'隋朝'),('EV223','李密瓦岗争雄','隋','洛口','李密成为瓦岗军首领，献计夺取洛口仓，声势大振，后与王世充决战失败，瓦岗军瓦解。',80,'隋朝'),('EV224','隋炀帝被弑','隋','江都','隋炀帝在江都被宇文化及缢杀，隋朝灭亡，他临死前想饮毒酒自尽，被叛军逼迫自缢。',100,'隋朝'),('EV225','李渊太原起兵','唐','太原','李渊在太原起兵反隋，李世民积极谋划，攻入长安，立代王杨侑为帝，后迫其禅位。',100,'唐朝建立'),('EV226','李世民平定薛仁杲','唐','浅水原','薛仁杲割据陇西，李世民率军征讨，在浅水原大败薛仁杲，平定陇西，消除唐朝侧翼威胁。',50,'唐朝建立'),('EV227','李世民平定刘武周','唐','洛阳','刘武周在突厥支持下南攻，李世民率军东征，在洛阳之战中消灭宋金刚，刘武周逃奔突厥。',50,'唐朝建立'),('EV228','李世民平定王世充','唐','洛阳','李世民围攻王世充于洛阳数月，王世充坚守待援，窦建德来救，被李世民虎牢关一举擒获。',80,'唐朝建立'),('EV229','虎牢关之战','唐','虎牢关','李世民以三千精骑大破窦建德十万大军，创造了军事史上以少胜多的经典战例。',100,'唐朝建立'),('EV230','玄武门之变','唐','长安','李世民在玄武门设伏，杀死太子李建成和齐王李元吉，迫使李渊立他为太子并禅位。',100,'玄武门之变'),('EV231','贞观之治','唐','长安','唐太宗李世民在位期间，轻徭薄赋，选贤任能，出现路不拾遗夜不闭户的治世景象。',100,'贞观之治'),('EV232','房玄龄杜如晦辅政','唐','长安','房玄龄和杜如晦是唐太宗最重要的两位宰相，"房谋杜断"成为千古佳话。',50,'贞观之治'),('EV233','魏征直谏','唐','长安','魏征是唐太宗最重要的谏臣，直言敢谏，前后上谏两百余事，太宗敬畏其人，开创了贞观纳谏之风。',80,'贞观之治'),('EV234','玄奘西行取经','唐','长安','玄奘独自一人西行取经，历经九死一生，到达印度，在那烂陀寺学习，回国后翻译佛经千余卷。',100,'贞观之治'),('EV235','李世民平定突厥','唐','突厥','唐太宗派李靖率军北击东突厥，在阴山之战中大破突厥，活捉颉利可汗，突厥汗国灭亡。',100,'贞观之治'),('EV236','文成公主入藏','唐','拉萨','唐太宗将文成公主嫁给吐蕃松赞干布，汉藏联姻促进了民族融合，文成公主带去的文化深刻影响了西藏。',100,'贞观之治'),('EV237','唐太宗征高句丽','唐','辽东','唐太宗亲征高句丽，虽有攻克，但未能灭国，最终撤兵，他自己也中箭受伤。',80,'贞观之治'),('EV238','薛延陀归附唐朝','唐','漠北','唐太宗派军击灭薛延陀，在漠北设置府州，任命铁勒部首领为都督，漠北纳入唐朝版图。',50,'贞观之治'),('EV239','唐高宗即位','唐','长安','唐高宗李治即位，初期继续贞观之治路线，后立武则天为皇后，唐朝进入新阶段。',50,'唐朝'),('EV240','长孙无忌辅政','唐','长安','长孙无忌是唐高宗的舅舅，也是贞观之治的功臣，受遗诏辅政，后被武则天迫害致死。',50,'唐朝'),('EV241','武则天入宫','唐','长安','唐高宗将才人武则天纳入后宫，武则天聪明机敏，逐渐参与朝政，成为中国历史上唯一的女皇帝。',100,'唐朝'),('EV242','武则天被立为皇后','唐','长安','唐高宗力排众议，立武则天为皇后，长孙无忌、褚遂良等元老重臣反对，武则天记恨在心。',80,'唐朝'),('EV243','唐高宗平定西突厥','唐','西域','苏定方率军击灭西突厥，在西域设置濛池都护府和昆陵都护府，唐朝疆域达到极盛。',50,'唐朝'),('EV244','武则天垂帘听政','唐','洛阳','唐高宗风疾发作，武则天开始垂帘听政，与皇帝并称"二圣"，权力日盛。',80,'唐朝'),('EV245','唐高宗逝世·武则天临朝','唐','洛阳','唐高宗病逝，武则天临朝称制，陆续废立皇帝，大权独揽，为称帝做准备。',50,'唐朝'),('EV246','徐敬业扬州起兵','唐','扬州','徐敬业等以恢复唐室为名在扬州起兵，骆宾王作《讨武曌檄》，武则天派兵镇压，起兵失败。',50,'唐朝'),('EV247','武则天称帝','周','洛阳','武则天称帝，改国号为周，成为中国历史上唯一的女皇帝，定都洛阳。',100,'武周时期'),('EV248','武则天酷吏政治','周','洛阳','武则天任用酷吏周兴、来俊臣等，大兴告密之风，迫害李唐宗室和元老大臣，冤案累累。',80,'武周时期'),('EV249','狄仁杰辅政','周','洛阳','狄仁杰是武则天最信任的宰相，以忠诚智慧著称，屡建奇功，也为恢复唐室做出了贡献。',80,'武周时期'),('EV250','武则天晚年张氏兄弟','周','洛阳','武则天晚年宠爱张易之、张昌宗兄弟，二张专权乱政，最终引发神龙政变。',50,'武周时期');
INSERT INTO `event_card` (`card_no`, `title`, `dynasty`, `location`, `description`, `weight`, `era`) VALUES
('EV251','神龙政变','唐','洛阳','张柬之、桓彦范等大臣发动神龙政变，逼迫武则天退位，李显复位，唐朝复辟。',100,'武周时期'),('EV252','唐中宗复位','唐','长安','李显在张柬之等扶持下复位，但韦后干政，朝政依然混乱，唐中宗实际上是个傀儡皇帝。',50,'唐朝'),('EV253','韦后之乱','唐','长安','韦后毒杀唐中宗，欲效仿武则天临朝称制，临淄王李隆基与太平公主发动唐隆政变，诛杀韦后。',80,'唐朝'),('EV254','李隆基诛太平公主','唐','长安','唐玄宗李隆基发动先天政变，捕杀太平公主及其党羽，彻底掌握了皇权，开始了开元盛世。',100,'开元盛世'),('EV255','开元盛世','唐','长安','唐玄宗在位初期，选贤任能，励精图治，唐朝经济繁荣，文化昌盛，开元盛世达到顶峰。',100,'开元盛世'),('EV256','姚崇宋璟辅政','唐','长安','姚崇、宋璟相继为相，整顿吏治，选拔人才，开元初年的清明政治有赖于这两位贤相。',50,'开元盛世'),('EV257','李白醉酒长安','唐','长安','李白被唐玄宗召入长安，供奉翰林，以诗才著称，玄宗常命其作诗助兴，高力士曾为其脱靴。',100,'开元盛世'),('EV258','杜甫困守长安','唐','长安','杜甫在长安困居十年，参加科举不第，作《兵车行》等诗反映民间疾苦，诗史之名由此奠定。',80,'开元盛世'),('EV259','安禄山范阳起兵','唐','范阳','安禄山以讨杨国忠为名，在范阳起兵叛乱，安史之乱爆发，唐朝由盛转衰的转折点。',100,'安史之乱'),('EV260','颜杲卿常山抗敌','唐','常山','颜真卿之兄颜杲卿在常山抵抗安禄山叛军，城破后被俘，骂贼不绝口，被割舌而死。',80,'安史之乱'),('EV261','高仙芝丧师小勃律','唐','小勃律','高仙芝远征小勃律，千里奔袭，攻下连云堡，但后来在怛罗斯被阿拉伯军队击败。',50,'唐朝'),('EV262','安禄山攻破洛阳','唐','洛阳','安禄山叛军攻破洛阳，唐东京留守李憕死之，洛阳沦陷，安禄山在洛阳自称大燕皇帝。',80,'安史之乱'),('EV263','马嵬驿之变','唐','马嵬驿','唐玄宗逃往蜀中，途经马嵬驿，随行将士饥疲愤怒，陈玄礼率兵杀死杨国忠，玄宗被迫缢死杨贵妃。',100,'安史之乱'),('EV264','李光弼守太原','唐','太原','李光弼以万余杂卒守太原，抵抗史思明十万大军，坚守城池不失，成为平定安史之乱的名将。',80,'安史之乱'),('EV265','张巡守睢阳','唐','睢阳','张巡以六千余人死守睢阳，抵抗尹子奇十余万大军，坚守十月，粮尽城破，张巡等三十六人全部殉国。',100,'安史之乱'),('EV266','李白从永王璘','唐','庐山','李白应永王李璘之邀入其幕府，作《永王东巡歌》，后永王谋反兵败，李白被流放夜郎。',80,'安史之乱'),('EV267','郭子仪收复长安','唐','长安','郭子仪率朔方军配合回纥兵收复长安，安史叛军大败，唐军乘胜收复东都洛阳。',80,'安史之乱'),('EV268','安史之乱结束','唐','洛阳','唐代宗继位后，安史降将仆固怀恩引回纥、吐蕃军反叛，郭子仪单骑入回纥营谈判，换来唐军大破敌军。',100,'安史之乱'),('EV269','黄巢起义·洛阳沦陷','唐末','洛阳','黄巢率农民军攻入洛阳，长安沦陷，唐僖宗仓皇南逃蜀中，唐朝中央权威瓦解，地方藩镇割据已成定局。',100,'唐朝末期'),('EV270','黄巢称帝·大齐立国','唐末','长安','黄巢在长安建立大齐政权，改元金统，农民起义达到顶峰，唐朝名存实亡。',95,'唐朝末期'),('EV271','李克用勤王·收复长安','唐末','长安','李克用率沙陀骑兵击败黄巢，收复长安，功封晋王，成为唐朝最重要的军事支柱。',90,'唐朝末期'),('EV272','黄巢败亡·狼虎谷覆灭','唐末','山东莱芜','黄巢在狼虎谷被围自杀，历时十年的唐末农民起义最终失败，但其动摇了唐朝根基。',90,'唐朝末期'),('EV273','宦官专权·神策军跋扈','唐末','长安','宦官把持神策军，废立皇帝，唐昭宗形同傀儡，皇权旁落至极点。',70,'唐朝末期'),('EV274','朱温降唐·开封崛起','唐末','开封','朱温降唐后被赐名全忠，封宣武节度使，以开封为基地势力日盛，为后来的后梁建立者。',85,'唐朝末期'),('EV275','唐昭宗继位·藩镇混战','唐末','长安','唐昭宗即位后试图振兴皇权，却引发藩镇之间更大规模的混战，朝廷威信扫地。',65,'唐朝末期'),('EV276','凤翔之战·李茂贞挟持天子','唐末','凤翔','李茂贞攻入长安，唐昭宗逃往凤翔被挟持，朝廷成为军阀手中的工具。',80,'唐朝末期'),('EV277','朱温攻凤翔·唐昭宗获救','唐末','凤翔','朱温率军击败李茂贞，迎接唐昭宗还京，昭宗从此落入朱温控制之下。',80,'唐朝末期'),('EV278','白马驿之祸·衣冠冢','唐末','开封','朱温在白马驿杀死唐昭宗及宦官三十余人，将尸体投入黄河，手段极其残忍。',85,'唐朝末期'),('EV279','朱温称帝·后梁建立','五代','开封','朱温废唐哀帝，建立后梁，改元开平，唐朝正式灭亡，中国历史进入五代十国时期。',100,'五代十国'),('EV280','后梁建国·朱温登基','五代','开封','朱温称帝建立后梁，都开封，是五代第一个政权，但北方局势始终未能完全统一。',90,'五代十国'),('EV281','沙陀崛起·李存勖继位','五代','太原','李克用之子李存勖继位晋王，沙陀势力在太原不断发展，成为后唐的奠基者。',85,'五代十国'),('EV282','柏乡之战·后梁惨败','五代','河北柏乡','李存勖在柏乡大败后梁主力骑兵，斩获甚众，后梁元气大伤。',85,'五代十国'),('EV283','后唐灭梁·李存勖称帝','五代','开封','李存勖攻入开封，后梁末帝朱友贞自杀，后唐建立，是五代版图最大的政权。',95,'五代十国'),('EV284','后唐明宗·元老政治','五代','洛阳','李嗣源继位为后唐明宗，励精图治，革除前朝弊政，出现短暂安定局面。',80,'五代十国'),('EV285','后唐内乱·闵帝遇难','五代','洛阳','后唐闵帝李从厚被潞王李从珂取代，兵变连连，皇位更迭频繁。',70,'五代十国'),('EV286','后晋建国·契丹册封','五代','开封','石敬瑭以割让燕云十六州为条件，在契丹支持下建立后晋，儿皇帝之名千古耻。',90,'五代十国'),('EV287','后晋出帝·对抗契丹','五代','开封','石敬瑭死后，其侄石重贵继位，拒绝向契丹称臣，两国关系破裂，战争再起。',75,'五代十国'),('EV288','契丹灭晋·中原沦陷','五代','开封','契丹军队攻入开封，后晋灭亡，契丹在中原建立短暂统治，掠夺惨重。',90,'五代十国'),('EV289','后汉建立·刘知远复国','五代','开封','刘知远趁契丹北撤之际在太原称帝，建立后汉，收复中原。',85,'五代十国'),('EV290','后汉隐帝·权臣当道','五代','开封','后汉隐帝刘承祐年幼，权臣郭威等掌控朝政，皇权有名无实。',60,'五代十国'),('EV291','郭威起兵·后周建立','五代','开封','郭威起兵推翻后汉，建立后周，励精图治，为北宋统一奠定基础。',90,'五代十国'),('EV292','后周世宗·柴荣北伐','五代','开封','周世宗柴荣是五代少有的英主，率军北伐契丹，收复三州三关。',95,'五代十国'),('EV293','高平之战·后周大捷','五代','山西高平','后周与北汉联军在高平激战，柴荣亲自督战，大败北汉，稳定了政权。',85,'五代十国'),('EV294','后周南征·统一南方','五代','长江流域','周世宗派兵南伐，先后攻占后蜀、南唐领土，为北宋统一全国做准备。',85,'五代十国'),('EV295','陈桥兵变·黄袍加身','五代','陈桥驿','赵匡胤在陈桥驿被部下拥立为帝，建立北宋，陈桥兵变兵不血刃，和平建国。',100,'五代十国'),('EV296','十国概览·割据政权','五代','各地','五代同时存在十个割据政权：前蜀、后蜀、南唐、吴越、闽、楚、南汉、南平、北汉、北宋完成统一。',60,'五代十国'),('EV297','南唐盛极·李煜治国','五代','金陵','南唐在李璟、李煜父子经营下成为十国中最富庶的文化中心，诗词璀璨。',70,'五代十国'),('EV298','后蜀花间派·文学繁荣','五代','成都','后蜀在孟昶统治下文化繁荣，花间派词人聚集，蜀中相对安定富庶。',65,'五代十国'),('EV299','吴越国·钱氏三代保境','五代','杭州','钱镠建立吴越国，采取保境安民政策，杭州城市建设和经济文化有显著发展。',70,'五代十国'),('EV300','闽国兴衰·王审知开闽','五代','福州','王审知建立闽国，采取保境安民政策，福建地区在五代乱世中相对安定。',65,'五代十国');
INSERT INTO `event_card` (`card_no`, `title`, `dynasty`, `location`, `description`, `weight`, `era`) VALUES
('EV301','南汉刘龑·极权统治','五代','广州','南汉刘龑建立大越国，统治残暴，使用诸多酷刑，南汉成为岭南割据政权。',60,'五代十国'),('EV302','北汉刘钧·倚靠契丹','五代','太原','北汉是十国中唯一的北方政权，倚靠契丹支持，与中原王朝长期对峙。',65,'五代十国'),('EV303','南平高氏·夹缝求生','五代','荆州','南平国小力弱，在各大国之间左右逢源，以卑微姿态维持生存数十年。',55,'五代十国'),('EV304','楚国马殷·茶叶立国','五代','长沙','马殷建立楚国，利用南方贸易通道大力发展茶叶经济，楚地一度繁荣。',65,'五代十国'),('EV305','后周征南唐·淮南之战','五代','扬州','后周世宗亲征南唐，夺取淮南十四州，南唐被迫去帝号割地求和。',85,'五代十国'),('EV306','赵匡胤削藩·集权中央','北宋','开封','宋太祖赵匡胤通过杯酒释兵权，解除石守信等大将兵权，确立中央集权制度。',100,'北宋初期'),('EV307','北宋灭后蜀·孟昶降宋','北宋','成都','宋军两路伐蜀，后蜀孟昶兵败出降，后蜀灭亡，宋朝统一四川。',85,'北宋初期'),('EV308','北宋灭南汉·刘鋹被俘','北宋','广州','宋太祖派兵灭南汉，刘鋹被俘，岭南地区重新归入中原王朝版图。',80,'北宋初期'),('EV309','南唐覆灭·李煜被俘','北宋','金陵','宋军攻破金陵，南唐后主李煜被俘，留下了千古绝唱《虞美人》等词作。',90,'北宋初期'),('EV310','北宋灭吴越·钱俶纳土','北宋','杭州','吴越国王钱俶顺应历史潮流，将吴越版图完整献给北宋，实现和平统一。',85,'北宋初期'),('EV311','宋太祖崩·太宗继位','北宋','开封','赵匡胤突然去世，其弟赵光义继位，是为宋太宗，烛影斧声成为千古之谜。',90,'北宋初期'),('EV312','宋太宗亲征·北汉覆灭','北宋','太原','宋太宗亲率大军攻灭北汉，十国割据局面彻底结束，中国大部分地区重归统一。',90,'北宋初期'),('EV313','高梁河之战·宋太宗败绩','北宋','北京高梁河','宋太宗北伐契丹，在高梁河大败，乘坐驴车仓皇逃回，雍熙北伐失败。',85,'北宋初期'),('EV314','杨家将传奇·抗辽名将','北宋','山西宁武','杨业在陈家谷口殉国，其抗辽事迹被民间传颂，形成杨家将忠勇传说。',80,'北宋初期'),('EV315','辽圣宗萧太后·萧燕燕摄政','辽','上京','萧太后萧燕燕以太后身份摄政，与宋缔结澶渊之盟，辽国进入鼎盛时期。',90,'辽朝全盛'),('EV316','澶渊之盟·宋辽和平','北宋','澶渊（今河南濮阳）','宋辽在澶渊订立和约，宋每年送辽银十万两绢二十万匹，换来百年和平。',100,'北宋初期'),('EV317','宋真宗封禅·泰山祭祀','北宋','泰山','宋真宗在王钦若怂恿下封禅泰山，耗费巨大，此举标志着北宋祥瑞政治的开端。',65,'北宋初期'),('EV318','刘太后垂帘·天圣执政','北宋','开封','刘太后临朝称制十余年，权力欲极强，宋仁宗形同傀儡，朝政由太后主导。',70,'北宋初期'),('EV319','庆历新政·范仲淹改革','北宋','开封','范仲淹等人推行庆历新政，改革吏治，整顿科举，但遭保守派反对而失败。',85,'北宋中期'),('EV320','仁宗亲政·嘉祐之治','北宋','开封','宋仁宗亲政后，勤政爱民，北宋经济文化高度繁荣，史称嘉祐之治。',80,'北宋中期'),('EV321','王安石变法·熙宁革新','北宋','开封','王安石在宋神宗支持下推行新法，包括青苗法、募役法等，旨在富国强兵，引发新旧党争。',100,'北宋中期'),('EV322','熙河开边·拓地千里','北宋','甘肃兰州','王韶率军攻占熙河地区，设置熙河路，北宋疆域一度大幅拓展。',85,'北宋中期'),('EV323','元祐党争·新旧党迭','北宋','开封','王安石新法被废除又复行，党争激烈，北宋政治陷入反复内耗的恶性循环。',80,'北宋中期'),('EV324','宋神宗崩·元丰改制','北宋','开封','宋神宗去世，高太后临朝，启用司马光尽废新法，史称元祐更化。',75,'北宋中期'),('EV325','哲宗亲政·绍圣复辟','北宋','开封','宋哲宗亲政后恢复新法，打击元祐旧臣，北宋党争进入白热化阶段。',75,'北宋中期'),('EV326','苏轼乌台诗案·文字狱','北宋','开封','苏轼因诗文中涉嫌讥讽新法，被押入御史台狱，几乎被判死刑，后贬为黄州团练副使。',80,'北宋中期'),('EV327','宋徽宗继位·蔡京当权','北宋','开封','宋徽宗即位，宠信蔡京，奸臣当道，朝政极度腐败，北宋走向衰亡。',85,'北宋末期'),('EV328','花石纲·艮岳兴建','北宋','开封','宋徽宗命朱勔搜刮江南奇花异石运往开封，建造艮岳，耗费民力无数，引发方腊起义。',75,'北宋末期'),('EV329','方腊起义·江南震动','北宋','浙江睦州','方腊以摩尼教为号召，在江南发动大规模起义，攻克六州五十二县，震撼北宋统治。',80,'北宋末期'),('EV330','宋江起义·梁山聚义','北宋','山东梁山','宋江等三十六人在梁山泊聚义，攻城掠地，后被张叔夜招降或征讨。',70,'北宋末期'),('EV331','童贯征辽·燕云之耻','北宋','开封','宋徽宗派童贯率军配合攻辽，结果宋军大败于辽兵，尽失联金灭辽的战略机遇。',85,'北宋末期'),('EV332','金朝建立·完颜阿骨打','金','上京会宁','完颜阿骨打在会宁称帝建立金朝，女真族崛起，迅速成为辽宋两国的巨大威胁。',95,'金朝兴起'),('EV333','海上之盟·宋金夹攻辽','北宋','开封','宋徽宗与金朝签订海上之盟，相约夹攻辽朝，但宋军表现拙劣，暴露了北宋的虚弱。',85,'北宋末期'),('EV334','金灭辽·辽天祚帝败亡','金','大同','金朝军队攻占辽上京，辽天祚帝西逃，辽朝灭亡，金朝成为中国北方新的霸主。',90,'金朝兴起'),('EV335','靖康之变·北宋覆亡','北宋','开封','金军攻破开封，掳走宋徽宗、宋钦宗及大量皇族、大臣北上，北宋灭亡。',100,'北宋末期'),('EV336','康王南渡·南宋建立','南宋','开封/杭州','赵构在南京应天府即位，后迁都临安，建立南宋，是为宋高宗。',100,'南宋初期'),('EV337','黄天荡之战·韩世忠抗金','南宋','镇江黄天荡','韩世忠率八千水军阻击金十万大军于黄天荡，梁红玉擂鼓助阵，传为千古佳话。',90,'南宋初期'),('EV338','岳飞北伐·郾城大捷','南宋','河南郾城','岳飞率岳家军北伐，在郾城大破金兵拐子马，进军朱仙镇，有望收复中原。',100,'南宋初期'),('EV339','十二道金牌·十年功废','南宋','开封','宋高宗和秦桧连发十二道金牌召回岳飞，以莫须有罪名将其杀害，北伐功败垂成。',100,'南宋初期'),('EV340','绍兴和议·宋金对峙','南宋','杭州','宋高宗与秦桧与金朝签订绍兴和议，宋向金称臣纳贡，以秦桧独相十七年换取和平。',95,'南宋初期'),('EV341','秦桧擅权·南宋黑暗期','南宋','杭州','秦桧独相十七年，排除异己，推行投降路线，南宋政治陷入空前黑暗。',75,'南宋初期'),('EV342','完颜亮南侵·采石之战','南宋','安徽采石','金海陵王完颜亮率六十万大军南下，虞允文在采石矶组织水战，大败金军。',90,'南宋中期'),('EV343','金世宗求治·小尧舜之治','金','中都','金世宗完颜雍在位期间，励精图治，与民休息，金朝出现中兴局面，史称小尧舜。',85,'金朝中期'),('EV344','隆兴北伐·符离之溃','南宋','安徽宿州','宋孝宗启用张浚北伐，在符离被金军击败，隆兴北伐失败，宋金重订和议。',75,'南宋中期'),('EV345','开禧北伐·韩侂胄主战','南宋','开封','韩侂胄发动开禧北伐，初有斩获，后因吴曦叛变而全面溃败。',80,'南宋中期'),('EV346','程朱理学·理学官方化','南宋','福建','朱熹继承发展理学，集理学之大成，后经官方认可成为正统儒学，影响中国后世七百年。',95,'南宋中期'),('EV347','成吉思汗崛起·蒙古建国','元','斡难河','铁木真统一蒙古各部，被推举为成吉思汗，建立大蒙古国，草原帝国横空出世。',100,'元朝兴起'),('EV348','蒙古西征·花剌子模覆灭','元','中亚','成吉思汗率军西征，摧毁花剌子模帝国，蒙古铁骑横扫中亚，威震欧洲。',90,'元朝兴起'),('EV349','蒙金战争·三峰山之战','元','河南钧州','蒙古与南宋联合灭金，在三峰山之战中全歼金军主力，金朝败局已定。',90,'元朝兴起'),('EV350','金朝覆亡·蔡州城破','金','河南汝南','蒙古军攻破蔡州，金哀宗完颜守绪自杀，金朝正式灭亡。',90,'金朝衰亡');
INSERT INTO `event_card` (`card_no`, `title`, `dynasty`, `location`, `description`, `weight`, `era`) VALUES
('EV351','蒙古灭西夏·中兴府陷落','元','宁夏银川','蒙古军包围中兴府，西夏末帝出降，西夏王朝覆灭。',85,'元朝兴起'),('EV352','钓鱼城之战·蒙哥汗陨落','南宋','重庆钓鱼城','蒙古大汗蒙哥在进攻钓鱼城时身亡，迫使蒙古军全线撤退，改变世界历史走向。',100,'南宋末期'),('EV353','忽必烈建元·元朝建立','元','大都','忽必烈在开平即汗位，后建国号大元，定都大都，北京从此成为中国的政治中心。',100,'元朝建立'),('EV354','襄阳保卫战·六年围城','南宋','湖北襄阳','蒙古（元）军围攻襄阳六年，南宋守将吕文焕苦撑危局，最终城破降元。',95,'南宋末期'),('EV355','文天祥抗元·起兵勤王','南宋','江西','文天祥在赣州起兵抗元，被俘后拒降，在狱中写下《正气歌》，从容就义。',90,'南宋末期'),('EV356','崖山之战·南宋覆亡','南宋','广东新会崖山','元军追击至崖山，陆秀夫负幼帝投海，南宋彻底覆亡，中国首次被外族完全统一。',100,'南宋末期'),('EV357','元朝统一·行省制度','元','大都','元朝统一中国后建立行省制度，开创中国省级行政区划先河，影响深远。',95,'元朝全盛'),('EV358','元朝四等人·民族压迫','元','大都','元朝将全国人民分为四等：蒙古人、色目人、汉人、南人，实行民族歧视政策。',80,'元朝统治'),('EV359','马可波罗来华·东方见闻','元','大都','意大利旅行家马可波罗抵达中国，在元朝任职十七年，其游记影响欧洲大航海时代。',85,'元朝全盛'),('EV360','郭守敬授时历·科技成就','元','大都','天文学家郭守敬编制《授时历》，其精确度在当时世界上首屈一指。',85,'元朝科技'),('EV361','元成宗守成·铁穆耳继位','元','大都','元成宗铁穆耳在位期间，继承忽必烈政策，元朝政治相对稳定。',70,'元朝中期'),('EV362','元武宗海山·财政紊乱','元','大都','元武宗海山滥发货币，导致财政紊乱，元朝经济开始出现问题。',65,'元朝中期'),('EV363','红巾军起义·元末农民战争','元','颍州','白莲教首领韩山童、刘福通发动红巾军起义，元末农民战争全面爆发。',90,'元朝末期'),('EV364','朱元璋崛起·集庆称王','元','南京','朱元璋加入红巾军后势力日盛，攻占集庆路改名应天府，自立为吴王。',95,'元朝末期'),('EV365','陈友谅称帝·汉政权','元','武昌','陈友谅杀死徐寿辉后在武昌称帝，建立陈汉政权，与朱元璋争夺天下。',80,'元朝末期'),('EV366','鄱阳湖大战·陈汉覆灭','元','江西鄱阳湖','朱元璋在鄱阳湖与陈友谅决战，以少胜多，陈友谅中箭身亡，汉政权灭亡。',90,'元朝末期'),('EV367','张士诚降元·东吴立国','元','苏州','张士诚在平江建立东吴政权，后受元朝招安成为方国珍式的割据势力。',75,'元朝末期'),('EV368','朱元璋北伐·驱逐胡虏','元','南京','朱元璋派徐达、常遇春率军北伐，发出驱逐胡虏、恢复中华的北伐檄文。',95,'元朝末期'),('EV369','明朝建立·洪武开元','元','南京','朱元璋在应天府称帝，建立明朝，是为明太祖，元朝在全国的统治结束。',100,'元朝末期'),('EV370','陈桥兵变','宋','陈桥驿（今河南开封）','赵匡胤被部下黄袍加身，拥立为帝，建立宋朝。',100,'宋'),('EV371','杯酒释兵权','宋','开封','宋太祖设宴款待石守信等开国功臣，暗示他们交出兵权。',80,'宋'),('EV372','澶渊之盟','宋','澶州','宋真宗与辽签订澶渊之盟，宋每年给辽银十万两绢二十万匹。',80,'宋'),('EV373','范仲淹变法','宋','开封','范仲淹推行庆历新政，提出改革方案，但被保守派推翻。',80,'宋'),('EV374','欧阳修革新文风','宋','开封','欧阳修提倡古文运动，反对骈体文，提倡平实朴素的文风。',80,'宋'),('EV375','王安石变法','宋','开封','宋神宗重用王安石，实行青苗法、募役法等新法。',100,'宋'),('EV376','司马光资治通鉴','宋','开封','司马光花费十九年编纂《资治通鉴》，是中国历史上最详尽的编年体通史。',80,'宋'),('EV377','宋徽宗艺术','宋','开封','宋徽宗在位期间书画艺术达到巅峰，瘦金体和工笔画均达到极致。',50,'宋'),('EV378','靖康之变','宋','开封','金兵攻破开封，俘虏宋徽宗、宋钦宗父子及大量皇族大臣，北宋覆亡。',100,'宋'),('EV379','岳飞北伐','宋','郾城','岳飞率岳家军北伐，在郾城大败金兵，但被宋高宗以十二道金牌召回。',100,'宋'),('EV380','秦桧陷岳飞','宋','临安','秦桧以莫须有罪名陷害岳飞，岳飞与其子岳云一同被害。',100,'宋'),('EV381','绍兴和议','宋','临安','宋金签订绍兴和议，宋向金称臣纳贡，以淮河为界。',80,'宋'),('EV382','隆兴北伐','宋','江淮','宋孝宗发动隆兴北伐，符离集溃败后被迫签订隆兴和议。',80,'宋'),('EV383','崖山海战','宋','崖山','蒙古军队在崖山海战击败宋军，陆秀夫负帝投海，南宋覆亡。',100,'宋'),('EV384','文天祥就义','宋','大都','文天祥被俘后拒绝投降，在大都从容就义，留有《正气歌》。',100,'宋'),('EV385','成吉思汗统一蒙古','元','斡难河','铁木真被推举为成吉思汗，建立蒙古帝国。',100,'元'),('EV386','蒙古灭西夏','元','中兴府（今宁夏）','蒙古军队包围中兴府，西夏灭亡，成吉思汗在征伐途中病逝。',80,'元'),('EV387','蒙古灭金','元','蔡州','蒙古与南宋联合灭金，金哀宗在蔡州自焚，金朝覆亡。',100,'元'),('EV388','忽必烈建元','元','大都','忽必烈改国号为元，建立元朝，定都大都。',100,'元'),('EV389','襄阳围城战','元','襄阳','蒙古军队围攻襄阳六年，宋军苦守，城破后南宋失去长江中游屏障。',100,'元'),('EV390','崖山之后','元','崖山','崖山海战结束，陆秀夫负幼帝投海，南宋彻底覆亡。',100,'元'),('EV391','元朝四等人制度','元','大都','元朝将全国人民分为蒙古人、色目人、汉人、南人四等。',50,'元'),('EV392','马可·波罗来华','元','大都','意大利旅行家马可·波罗抵达大都，在元朝任职十七年。',80,'元'),('EV393','郭守敬修订历法','元','大都','郭守敬编制《授时历》，是当时世界上最精确的历法。',80,'元'),('EV395','刘福通起兵颍州','元','颍州（今安徽阜阳）','刘福通在颍州发动红巾军起义，各地纷纷响应，元朝统治开始动摇。',90,'元末'),('EV396','芝麻李彭大起义','元','徐州','芝麻李等人在徐州发动红巾军起义，声势浩大，元朝调集重兵镇压。',70,'元末'),('EV397','郭子兴起兵濠州','元','濠州（今安徽凤阳）','郭子兴在濠州响应红巾军起义，后来成为朱元璋加入的队伍。',80,'元末'),('EV398','彭莹玉传教布道','元','淮西地区','白莲教僧人彭莹玉在淮西传播白莲教，组织发动红巾军起义。',50,'元末'),('EV399','徐寿辉建天完国','元','蕲水','徐寿辉在蕲水建立天完国，与红巾军呼应，成为元末农民起义的重要力量。',80,'元末'),('EV400','脱脱主政改革','元','大都','丞相脱脱推行改革，整顿吏治，但因得罪权贵被贬，改革半途而废。',50,'元末'),('EV401','高邮之战','元','高邮（今江苏）','张士诚在高邮大败元军，元朝围攻高邮不下，元军内部发生政变，脱脱被罢官。',85,'元末');
INSERT INTO `event_card` (`card_no`, `title`, `dynasty`, `location`, `description`, `weight`, `era`) VALUES
('EV402','元顺帝怠政','元','大都','元顺帝怠于政事，荒淫无度，朝政混乱，宫廷内部斗争不断。',50,'元末'),('EV403','朱元璋投奔郭子兴','元','濠州','朱元璋加入郭子兴的红巾军，因聪明能干被赏识，将养女马氏嫁给他。',90,'元末'),('EV404','朱元璋攻取集庆','元','集庆（今南京）','朱元璋率军攻取集庆，改名应天府，作为自己的根据地，开始独立发展。',90,'元末'),('EV405','小明王韩林儿','元','亳州','韩林儿称小明王，继承刘福通的红巾军势力，朱元璋一度名义上归附。',70,'元末'),('EV406','陈友谅杀徐寿辉','元','江州','陈友谅杀徐寿辉自立为帝，建立汉国，成为朱元璋最强的对手。',85,'元末'),('EV407','鄱阳湖之战','元','鄱阳湖','朱元璋与陈友谅在鄱阳湖展开决战，朱元璋以少胜多，陈友谅战死。',100,'元末'),('EV408','张士诚自称吴王','元','平江（今苏州）','张士诚在平江自称吴王，割据江浙富庶地区，与朱元璋对峙。',80,'元末'),('EV409','朱元璋平定陈友谅','元','武昌','朱元璋攻灭陈友谅的汉国，统一了长江中游，为建立明朝奠定基础。',90,'元末'),('EV410','朱元璋北伐灭元','明','大都','朱元璋命徐达、常遇春率军北伐，元顺帝北逃，元朝在中原的统治结束。',100,'明朝建立'),('EV411','朱元璋称帝建明','明','南京','朱元璋在南京称帝，建立明朝，年号洪武，开启汉族王朝统治。',100,'明朝初期'),('EV412','朱元璋大封功臣','明','南京','朱元璋大封功臣，李善长、徐达等被封为公爵，功臣集团形成。',50,'明朝初期'),('EV413','胡惟庸案','明','南京','朱元璋以胡惟庸谋反案为由，大兴牢狱，牵连死者数万人，废除丞相制度。',90,'明朝初期'),('EV414','空印案','明','南京','朱元璋严惩空白盖印文书之罪，地方官员多受牵连，株连无数。',50,'明朝初期'),('EV415','郭桓案','明','南京','户部侍郎郭桓贪污事发，朱元璋严加追查，牵连无数，全国中等门户多破产。',50,'明朝初期'),('EV416','洪武大诰','明','南京','朱元璋亲自编写《大诰》，以案例警示官员，整顿吏治。',50,'明朝初期'),('EV417','蓝玉案','明','南京','朱元璋以蓝玉谋反案为由，大肆诛杀功臣将领，株连一万五千余人。',85,'明朝初期'),('EV418','锦衣卫设立','明','南京','朱元璋设立锦衣卫，作为侍从皇帝的军事机构，兼管侦察逮捕。',80,'明朝初期'),('EV419','朱元璋分封诸王','明','南京','朱元璋将儿子分封到各地为藩王，以屏卫皇室，结果导致靖难之役。',50,'明朝初期'),('EV420','徐达北征沙漠','明','北方边疆','徐达率军北征沙漠，打击北元势力，明朝边界暂时稳定。',80,'明朝初期'),('EV421','刘伯温去世','明','南京','刘伯温辞官归里，被胡惟庸党羽毒杀，一代谋士陨落。',70,'明朝初期'),('EV422','朱元璋病逝','明','南京','朱元璋病逝，皇太孙朱允炆即位，是为建文帝，遗诏不允许藩王进京奔丧。',80,'明朝初期'),('EV423','建文帝削藩','明','南京','建文帝采纳齐泰、黄子澄建议，开始削藩，周王等藩王相继被废。',85,'靖难之役'),('EV424','燕王起兵靖难','明','北平','朱棣以清君侧为名，在北平起兵反抗，史称靖难之役。',100,'靖难之役'),('EV425','靖难三杰','明','北平','朱棣帐下姚广孝、解缙、胡广等谋士，成为靖难之役的核心人物。',50,'靖难之役'),('EV426','朱允炆失踪之谜','明','南京','朱棣攻入南京，建文帝在混乱中下落不明，成为千古之谜。',100,'靖难之役'),('EV427','永乐帝迁都北京','明','北京','朱棣迁都北京，以天子守国门的方式加强对北方边疆的控制。',90,'永乐盛世'),('EV428','郑和下西洋','明','南京','郑和率船队出使西洋，历时二十八年，到达三十余国，开创了大航海时代。',100,'永乐盛世'),('EV429','解缙编纂永乐大典','明','南京','解缙等编纂永乐大典，是中国历史上最大百科全书。',80,'永乐盛世'),('EV430','永乐帝亲征漠北','明','漠北','朱棣亲率大军北征漠北，五出塞外，打击蒙古势力。',90,'永乐盛世'),('EV431','土木堡之变','明','土木堡','明英宗御驾亲征瓦剌，在土木堡被俘，明朝由盛转衰。',100,'明代中后期'),('EV432','于谦守北京','明','北京','北京保卫战，于谦力挽狂澜，击退瓦剌大军，挽救了明朝。',100,'明代中后期'),('EV433','夺门之变','明','北京','明英宗复位，于谦被害，明朝政治陷入动荡。',80,'明代中后期'),('EV434','弘治中兴','明','北京','明孝宗励精图治，重用贤臣，明朝出现中兴局面。',70,'明代中后期'),('EV435','宁王朱宸濠之乱','明','南昌','宁王朱宸濠在南昌起兵谋反，被王阳明平定。',80,'明代中后期'),('EV436','王阳明平宁王之乱','明','南昌','王阳明以少胜多，迅速平定宁王之乱，展现了心学的实践力量。',85,'明代中后期'),('EV437','大礼议之争','明','北京','群臣与嘉靖帝就生父称号发生激烈争论，最终嘉靖帝获胜。',50,'明代中后期'),('EV438','戚继光抗倭','明','浙江','戚继光在浙江招募矿工，训练戚家军，平定东南沿海倭患。',100,'明代中后期'),('EV439','俺答封贡','明','大同','明朝封俺答为顺义王，在大同开互市，结束了与蒙古的多年战争。',80,'明代中后期'),('EV440','隆庆开关','明','月港','明朝解除海禁，允许民间赴海外贸易，月港成为主要出海口。',70,'明代中后期'),('EV441','张居正改革','明','北京','张居正推行一条鞭法等改革，整顿吏治，明朝出现短暂中兴。',100,'明代中后期'),('EV442','万历三大征','明','宁夏/朝鲜/播州','万历皇帝派兵平定宁夏哱拜之乱、抗击日本侵朝、征讨播州杨应龙。',85,'明代中后期'),('EV443','哥伦布发现美洲','明','美洲','哥伦布航行到达美洲，开启了全球史的新纪元。',100,'世界史'),('EV444','达·伽马到达印度','明','印度','达·伽马绕过好望角到达印度，开辟了欧洲到亚洲的新航路。',90,'世界史'),('EV445','马丁·路德宗教改革','明','德国','马丁·路德在维登堡发表九十五条论纲，宗教改革运动席卷欧洲。',100,'世界史'),('EV446','哥白尼日心说','明','波兰','哥白尼发表《天体运行论》，提出日心说，颠覆了中世纪的宇宙观。',90,'世界史'),('EV447','丰臣秀吉侵朝','明','朝鲜','日本关白丰臣秀吉率军入侵朝鲜，明朝派兵援朝，中日朝三国大战。',90,'明代中后期'),('EV448','李时珍本草纲目','明','武汉','李自成编纂《本草纲目》，是中医药学的里程碑著作。',80,'明代中后期'),('EV449','徐光启译几何原本','明','北京','徐光启与利玛窦合作翻译《几何原本》，开启了西学东渐的潮流。',70,'明代中后期'),('EV450','徐霞客游记','明','江阴','徐霞客游历天下三十余年，写成《徐霞客游记》，是地理学瑰宝。',70,'明代中后期'),('EV451','明末三大儒','明','江浙','顾炎武、黄宗羲、王夫之批判君主专制，提出初步的民主思想。',80,'明末');
INSERT INTO `event_card` (`card_no`, `title`, `dynasty`, `location`, `description`, `weight`, `era`) VALUES
('EV452','东林党议','明','无锡','东林党人与阉党在朝堂上激烈争论，明朝政治日益黑暗。',70,'明末'),('EV453','魏忠贤专权','明','北京','宦官魏忠贤操纵朝政，迫害东林党人，自称九千岁。',80,'明末'),('EV454','崇祯帝即位','明','北京','崇祯帝即位后铲除魏忠贤，但明朝积重难返，气数已尽。',70,'明末'),('EV455','徐光启红桌计画','明','北京','徐光启提出红桌计画，在京城训练火器手抵御后金。',50,'明末'),('EV456','袁崇焕守宁远','明','宁远','袁崇焕在宁远大败努尔哈赤，努尔哈赤因伤去世。',90,'明末'),('EV457','皇太极建国大清','明','沈阳','皇太极改后金为大清，在沈阳称帝，开始入关的准备。',90,'明末清初'),('EV458','袁崇焕被诛','明','北京','崇祯帝中反间计，以谋反罪处死袁崇焕，自毁长城。',100,'明末'),('EV459','高迎祥起义','明','陕西','高迎祥在陕西发动农民起义，成为闯王高迎祥的起源。',80,'明末'),('EV460','李自成闯王','明','西安','李自成继任闯王，提出均田免粮的口号，深得民心。',85,'明末'),('EV461','张献忠建立大西','明','成都','张献忠在成都建立大西国，与李自成遥相呼应。',80,'明末'),('EV462','洪承畴降清','明','锦州','洪承畴兵败松锦，被皇太极招降，成为清朝入关的重要帮手。',70,'明末清初'),('EV463','吴三桂降清','明','山海关','李自成攻入北京，吴三桂引清兵入关，在山海关大败李自成。',100,'明末清初'),('EV464','崇祯帝煤山自缢','明','北京','李自成攻入北京，崇祯帝在煤山自缢，明朝覆亡。',100,'明末'),('EV465','扬州十日','清','扬州','清军攻破扬州，多铎下令屠杀十日，扬州百姓死伤无数。',100,'清初'),('EV466','嘉定三屠','清','嘉定','清军攻破嘉定，因反抗剃发令，三次屠杀嘉定城。',100,'清初'),('EV467','郑成功收复台湾','清','台湾','郑成功率军驱逐荷兰殖民者，收复台湾，建立郑氏政权。',100,'清初'),('EV468','康熙帝擒鳌拜','清','北京','康熙帝在宫中使用计谋擒拿权臣鳌拜，开始亲政。',90,'清初');
INSERT INTO `event_card` (`card_no`, `title`, `dynasty`, `location`, `description`, `weight`, `era`) VALUES
('EV394','察罕帖木儿镇压红巾军','元','安徽/河南','元朝：郭子兴部将察罕帖木儿镇压红巾军，在安徽、河南一带屡建战功，成为元朝镇压农民起义的主要将领。',50,'元末'),
('EV469','康熙平三藩·三藩之乱','清','云南/广东/福建','康熙帝下令削藩，平定吴三桂、尚可喜、耿精忠三藩之乱，稳固了清朝对全国的统治。',50,'清代初期'),
('EV470','康熙收复台湾·统一台湾','清','台湾','康熙二十二年，施琅率清军攻台，郑克塽投降，台湾纳入清朝版图。',90,'清代初期'),
('EV471','雅克萨之战·抗击沙俄','清','雅克萨（今黑龙江）','康熙帝两次出兵雅克萨，大败沙俄侵略军，签订《尼布楚条约》，划定东北边界。',80,'清代初期'),
('EV472','康熙亲征噶尔丹·漠北安定','清','漠北','康熙帝三次亲征噶尔丹，平定准噶尔叛乱，稳定了漠北蒙古局势。',80,'清代初期'),
('EV473','康熙九子夺嫡','清','北京','康熙帝晚年，诸皇子争夺皇位继承权，最终皇四子胤禛胜出，是为雍正帝。',80,'清代初期'),
('EV474','雍正帝即位·清理吏治','清','北京','雍正帝即位，励精图治，推行养廉银、火耗归公等改革，整顿吏治。',50,'清代初期'),
('EV475','摊丁入亩·税制改革','清','全国','雍正帝推行摊丁入亩，将人头税并入土地税，简化税收制度，减轻无地农民负担。',50,'清代初期'),
('EV476','军机处设立','清','北京','雍正帝设立军机处，作为皇帝的机要秘书机构，进一步强化中央集权。',100,'清代初期'),
('EV477','康乾盛世·人口增长','清','全国','康熙、雍正、乾隆三朝盛世期间，社会稳定，人口从一亿激增至三亿。',50,'清代中期'),
('EV478','土司改流·西南安定','清','西南地区','雍正朝大规模推行改土归流，废除土司世袭制度，改派流官管理西南地区。',50,'清代初期'),
('EV479','文字狱·清代思想控制','清','全国','康雍乾三朝大兴文字狱，因言获罪者众多，严重压制了思想文化的发展。',50,'清代中期'),
('EV480','四库全书·乾隆文化工程','清','北京','乾隆帝主持编纂《四库全书》，收录典籍万余部，是世界上规模最大的丛书。',80,'清代中期'),
('EV481','乾隆帝南巡·六下江南','清','江南','乾隆帝六次南巡，视察水利，笼络江南士子，展示大清国威。',80,'清代中期'),
('EV482','马戛尔尼使华·清朝闭国','清','北京','英国使节马戛尔尼访华，因礼节之争谈判破裂，清朝错失了解西方机会。',50,'清代中期'),
('EV483','和珅跌倒·嘉庆吃饱','清','北京','乾隆帝宠臣和珅贪污腐败，嘉庆帝即位后将其抄家，和珅家产抵国库十数年。',80,'清代中期'),
('EV484','白莲教起义·川楚白莲教起事','清','四川/湖北','白莲教在川楚地区发动大起义，历时九年，清朝耗资两亿两方才镇压。',100,'清代中期'),
('EV485','鸦片输入·白银外流','清','广州','英国向中国走私鸦片，银贵钱贱，白银大量外流，清朝经济受到严重冲击。',80,'清代中期'),
('EV486','林则徐虎门销烟','清','虎门（今广东）','林则徐在虎门销毁鸦片两万余箱，向世界宣示了中国禁烟的决心。',100,'清代中期'),
('EV487','鸦片战争·南京条约','清','广州/南京','鸦片战争爆发，清朝战败，签订《南京条约》，割让香港，开放五口通商。',90,'清代中期'),
('EV488','太平天国起义·金田起义','清','桂平金田','洪秀全在广西金田发动起义，建号太平天国，太平天国运动正式爆发。',50,'清代中期'),
('EV489','太平军定都南京·建都天京','清','南京','太平军攻占南京改名天京并定都于此，与清朝对峙长达十余年。',80,'清代中期'),
('EV490','曾国藩湘军·镇压太平天国','清','湖南/南京','曾国藩以团练起家创建湘军，成为镇压太平天国的主力，挽救清朝。',100,'清代中期'),
('EV491','太平天国北伐西征','清','北方/长江流域','太平天国发动北伐直逼北京，西征巩固长江上游，军事上达到全盛。',90,'清代中期'),
('EV492','天京陷落·太平天国覆亡','清','南京','湘军攻破天京，洪秀全病逝，太平天国运动失败，历时十四年。',90,'清代中期'),
('EV493','第二次鸦片战争·火烧圆明园','清','北京','英法联军攻入北京，火烧圆明园，签订《北京条约》，中国半殖民地化加深。',80,'清代中期'),
('EV494','洋务运动·自强求富','清','全国','洋务派以自强求富为口号，创办近代军事工业和民用企业。',80,'清代中期'),
('EV495','甲午战争·黄海海战','清','黄海','北洋水师与日本联合舰队在黄海激战，清军战败，李鸿章苦心经营的舰队覆灭。',90,'清代中期'),
('EV496','马关条约·割让台湾','清','马关/台湾','甲午战败后签订《马关条约》，割让台湾及辽东半岛，赔款白银两亿两。',50,'清代中期'),
('EV497','戊戌变法·百日维新','清','北京','康有为、梁启超发动戊戌变法，光绪帝颁布新政诏书，慈禧发动政变，变法失败。',50,'清代中期'),
('EV498','义和团运动·扶清灭洋','清','北京/山东','义和团打出扶清灭洋旗号，慈禧太后利用义和团，八国联军侵华。',100,'清代末期'),
('EV499','八国联军侵华·辛丑条约','清','北京','八国联军攻入北京，签订《辛丑条约》，中国彻底沦为半殖民地半封建社会。',50,'清代末期'),
('EV500','辛亥革命·武昌起义','清','武昌','辛亥革命爆发，武昌起义成功，中华民国成立，清朝统治结束。',90,'清代末期'),
('EV501','孙中山创立同盟会','清','东京','孙中山在东京成立同盟会，以驱除鞑虏、恢复中华、建立民国、平均地权为纲领。',90,'近代'),
('EV502','黄花岗起义','清','广州','同盟会在广州发动黄花岗起义，七十二烈士殉国，震动全国。',90,'近代'),
('EV503','辛亥革命·南北议和','清','南京/北京','辛亥革命后，孙中山与袁世凯进行南北议和，清帝退位，中华民国建立。',50,'近代'),
('EV504','中华民国成立·孙中山就职','民国','南京','孙中山在南京就任中华民国临时大总统，亚洲第一个共和国诞生。',100,'近代'),
('EV505','袁世凯称帝·洪宪帝制','民国','北京','袁世凯称帝，改元洪宪，蔡锷等发动护国战争，袁世凯被迫取消帝制。',50,'近代'),
('EV506','五四运动·新民主主义开端','民国','北京','北京学生示威抗议巴黎和会，五四运动爆发，揭开中国新民主主义革命序幕。',100,'近代'),
('EV507','中国共产党成立·一大召开','民国','上海','中共一大在上海召开，中国共产党成立，中国革命面貌焕然一新。',50,'近代'),
('EV508','北伐战争·国民革命军北伐','民国','广州/北京','国共合作北伐，国民革命军势如破竹，基本推翻北洋军阀统治。',90,'近代'),
('EV509','四一二政变·蒋介石清党','民国','上海','蒋介石发动四一二政变，大肆捕杀共产党员，国共合作破裂。',90,'近代'),
('EV510','南昌起义·建军节起源','民国','南昌','中共在南昌发动起义，打响武装反抗国民党第一枪，8月1日定为建军节。',80,'近代'),
('EV511','井冈山会师·红色根据地','民国','井冈山','朱德、陈毅与毛泽东在井冈山会师，建立第一个红色根据地。',50,'近代'),
('EV512','红军长征·战略转移','民国','中国西部','中央红军长征，历时两年，行程二万五千里，最终到达陕北。',50,'近代'),
('EV513','九一八事变·日本侵占东北','民国','沈阳','日本关东军发动九一八事变，侵占东北三省，抗日战争拉开序幕。',80,'近代'),
('EV514','一二八事变·上海抗战','民国','上海','日军进攻上海，第十九路军奋起抵抗，第一次淞沪抗战爆发。',90,'近代'),
('EV515','长城抗战·何梅协定','民国','北京/河北','中国军队在长城沿线抵抗日军，签订《何梅协定》，华北门户洞开。',50,'近代'),
('EV516','七七事变·全面抗战爆发','民国','卢沟桥','日军在卢沟桥发动进攻，全面抗战爆发，中华民族全面抵抗。',80,'近代'),
('EV517','淞沪会战·八百壮士','民国','上海','中国军队在淞沪会战中浴血奋战，四行仓库八百壮士孤军守阵。',50,'近代');
INSERT INTO `event_card` (`card_no`, `title`, `dynasty`, `location`, `description`, `weight`, `era`) VALUES
('EV518','南京大屠杀·三十万同胞遇难','民国','南京','日军攻占南京，进行长达六周的大屠杀，遇难同胞达三十万人。',100,'近代'),
('EV519','台儿庄战役·抗战首捷','民国','台儿庄','李宗仁指挥台儿庄战役，歼敌万余人，取得抗战以来最大胜利。',90,'近代'),
('EV520','百团大战·敌后战场','民国','华北','彭德怀指挥百团大战，八路军主动出击，歼敌四万余人。',100,'近代'),
('EV521','皖南事变·新四军损失','民国','皖南','国民党顽固派发动皖南事变，围攻新四军，军长叶挺被扣，项英牺牲。',90,'近代'),
('EV522','三大战役·解放战争决战','民国','东北/华北/华东','辽沈、淮海、平津三大战役胜利，国民党军队主力基本被歼灭。',80,'近代'),
('EV523','渡江战役·解放南京','民国','长江/南京','人民解放军渡江作战，攻占南京，国民党政权覆灭。',90,'近代'),
('EV524','中华人民共和国成立·开国大典','现代','北京','毛泽东在天安门城楼宣布中华人民共和国成立，中国人民站起来了。',90,'现代'),
('EV525','抗美援朝·保家卫国','现代','朝鲜','中国人民志愿军入朝作战，与美军等联合国军激战三年，逼和美国。',80,'现代'),
